function save_current_figure_local(hfig, fig_out_dir, base_name, ...
    save_png, save_matlab_fig, png_dpi)

if ~exist(fig_out_dir, 'dir')
    mkdir(fig_out_dir);
end

if save_png
    png_file = fullfile(fig_out_dir, sprintf('%s.png', base_name));
    save_png_local(hfig, png_file, png_dpi);
    fprintf('\nSaved PNG figure:\n  %s\n', png_file);
end

if save_matlab_fig
    fig_file = fullfile(fig_out_dir, sprintf('%s.fig', base_name));
    savefig(hfig, fig_file);
    fprintf('Saved MATLAB figure:\n  %s\n', fig_file);
end
end

function save_png_local(fig, pngFile, dpi)
drawnow;

try
    if exist('exportgraphics', 'file') == 2
        exportgraphics(fig, pngFile, ...
            'Resolution', dpi, ...
            'BackgroundColor', 'white');
    else
        set(fig, 'PaperPositionMode', 'auto');
        print(fig, pngFile, '-dpng', sprintf('-r%d', dpi));
    end
catch
    warning('exportgraphics/print failed. Falling back to saveas.');
    saveas(fig, pngFile);
end
end

function name = sanitize_filename_local(name)
if isstring(name)
    name = char(name);
end

name = regexprep(name, '[^a-zA-Z0-9_\-]', '_');
name = regexprep(name, '_+', '_');
name = strtrim(name);

if isempty(name)
    name = 'unnamed';
end
end

function [nRows, nCols] = choose_panel_layout_local(nPanels, max_panel_cols)
if nPanels < 1
    error('nPanels must be >= 1.');
end

if nargin < 2 || isempty(max_panel_cols)
    max_panel_cols = 4;
end

max_panel_cols = max(1, max_panel_cols);
max_panel_cols = min(max_panel_cols, nPanels);

best_score = inf;
best_rows = 1;
best_cols = 1;

for c = 1:max_panel_cols
    r = ceil(nPanels / c);
    empty_panels = r * c - nPanels;

    % Prefer layouts close to square, but slightly wider than tall.
    aspect_penalty = abs(c / r - 1.35);

    % Strongly penalize empty panels.
    empty_penalty = empty_panels * 10;

    % Mildly penalize too many rows.
    row_penalty = r * 0.1;

    score = empty_penalty + aspect_penalty + row_penalty;

    if score < best_score
        best_score = score;
        best_rows = r;
        best_cols = c;
    end
end

nRows = best_rows;
nCols = best_cols;
end

function mode_tag = model_mode_to_file_tag_local(model_mode)
